import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  FiShield, 
  FiArrowLeft, 
  FiUsers, 
  FiCalendar, 
  FiDollarSign,
  FiTrendingUp,
  FiUserPlus,
  FiSettings,
  FiLogOut,
  FiBarChart,
  FiCheckCircle,
  FiClock,
  FiXCircle
} from 'react-icons/fi';
import { useAuth } from '../context/AuthContext';
import { Booking, Employee, ContactQuery } from '../types';
import { apiService } from '../services/api';
import { API_ENDPOINTS } from '../config/api';
import { useQuery } from 'react-query';
import toast from 'react-hot-toast';
import axios from 'axios';
import ReactModal from 'react-modal';
ReactModal.setAppElement('#root');

const AdminDashboard: React.FC = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'overview' | 'bookings' | 'employees' | 'queries'>('overview');
  const [bookingsTab, setBookingsTab] = useState<'all' | 'pending' | 'accepted' | 'completed'>('all');
  const [selectedBooking, setSelectedBooking] = useState<any | null>(null);
  const [isBookingModalOpen, setIsBookingModalOpen] = useState(false);
  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assigningBooking, setAssigningBooking] = useState<any | null>(null);
  const [selectedTechnician, setSelectedTechnician] = useState<string>('');
  const [isVerifying, setIsVerifying] = useState(false);
  const [isAssigning, setIsAssigning] = useState(false);

  // No strict user.id or user.name checks here; just rely on ProtectedRoute
  const sessionId = localStorage.getItem('sessionId');
  // Fetch dashboard data
  const { data: bookingsData, isLoading: bookingsLoading } = useQuery(
    'admin-bookings',
    () => apiService.get<{ bookings: Booking[] }>(`${API_ENDPOINTS.ADMIN_ORDERS}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load bookings');
      }
    }
  );

  const { data: employeesData, isLoading: employeesLoading } = useQuery(
    'employees',
    () => apiService.get<{ employees: Employee[] }>(`${API_ENDPOINTS.GET_TECHNICIANS}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load employees');
      }
    }
  );

  const { data: queriesData, isLoading: queriesLoading } = useQuery(
    'contact-queries',
    () => apiService.get<{ queries: ContactQuery[] }>(`${API_ENDPOINTS.ADMIN_CONTACT_QUERIES}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load contact queries');
      }
    }
  );

  // Combine bookings arrays from API response (pending, completed, accepted)
  const bookingsDataAny = bookingsData as any;
  const bookings = [
    ...(bookingsDataAny?.orders?.pending || []),
    ...(bookingsDataAny?.orders?.completed || []),
    ...(bookingsDataAny?.orders?.accepted || [])
  ];

  // Employees: use data array from API response and map to UI model
  const employeesDataAny = employeesData as any;
  const employees = (employeesDataAny?.data || []).map((emp: any) => ({
    id: emp.technician_id,
    name: emp.employee_name,
    email: emp.email,
    mobile: emp.phone_number,
    serviceType: emp.service_type,
    address: emp.address,
    idProof: emp.id_proof,
  }));

  // Combine queries arrays if nested (adjust as needed)
  const queriesDataAny = queriesData as any;
  const queries = queriesDataAny?.queries || queriesDataAny?.data?.queries || [];

  // Add explicit types to map/filter/reduce parameters
  const totalBookings = bookings.length;
  const pendingBookings = bookings.filter((b: Booking) => b.status === 'pending').length;
  const completedBookings = bookings.filter((b: Booking) => b.status === 'completed').length;
  const totalRevenue = bookings.reduce((sum: number, b: Booking) => sum + b.total_amount, 0);
  const pendingQueries = queries.filter((q: ContactQuery) => q.status === 'pending').length;

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed':
        return 'bg-green-100 text-green-800';
      case 'accepted':
        return 'bg-blue-100 text-blue-800';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'cancelled':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const statsCards = [
    {
      title: 'Total Bookings',
      value: totalBookings,
      icon: FiCalendar,
      color: 'bg-blue-500',
      change: '+12%'
    },
    {
      title: 'Pending Bookings',
      value: pendingBookings,
      icon: FiClock,
      color: 'bg-yellow-500',
      change: '+5%'
    },
    {
      title: 'Total Revenue',
      value: `₹${totalRevenue.toLocaleString()}`,
      icon: FiDollarSign,
      color: 'bg-green-500',
      change: '+18%'
    },
    {
      title: 'Active Employees',
      value: employees.length,
      icon: FiUsers,
      color: 'bg-purple-500',
      change: '+2'
    }
  ];

  function handleResetPassword(technicianId: string) {
    if (window.confirm('Are you sure you want to reset the password for this employee? The new password will be set to "12345".')) {
      const sessionId = localStorage.getItem('sessionId');
      axios.post(`${process.env.REACT_APP_API_BASE_URL || ''}reset_password.php`, {
        technician_id: technicianId,
        newpassword: '12345',
      }, {
        headers: {
          'Content-Type': 'application/json',
          'Session-ID': sessionId || '',
        },
      })
        .then((response) => {
          alert(response.data.message || 'Password reset successful!');
        })
        .catch(() => {
          alert('Failed to reset password. Please try again.');
        });
    }
  }

  function handleViewBooking(booking: any) {
    setSelectedBooking(booking);
    setIsBookingModalOpen(true);
  }

  function handleCloseBookingModal() {
    setIsBookingModalOpen(false);
    setSelectedBooking(null);
  }

  function handleVerifyBooking(bookingId: string) {
    if (!window.confirm('Are you sure you want to verify this booking?')) return;
    setIsVerifying(true);
    const sessionId = localStorage.getItem('sessionId');
    axios.post(`${process.env.REACT_APP_API_BASE_URL || ''}update_order_status.php`, {
      booking_id: bookingId,
      new_status: 'confirmed',
    }, {
      headers: {
        'Content-Type': 'application/json',
        'Session-ID': sessionId || '',
      },
    })
      .then((response) => {
        alert(response.data.message || 'Booking verified!');
        window.location.reload();
      })
      .catch(() => {
        alert('Failed to verify booking. Please try again.');
      })
      .finally(() => setIsVerifying(false));
  }

  function handleOpenAssignModal(booking: any) {
    setAssigningBooking(booking);
    setIsAssignModalOpen(true);
    setSelectedTechnician('');
  }

  function handleCloseAssignModal() {
    setIsAssignModalOpen(false);
    setAssigningBooking(null);
    setSelectedTechnician('');
  }

  function handleAssignTechnician() {
    if (!selectedTechnician) {
      alert('Please select a technician.');
      return;
    }
    setIsAssigning(true);
    const sessionId = localStorage.getItem('sessionId');
    axios.post(`${process.env.REACT_APP_API_BASE_URL || ''}assign_technician.php`, {
      booking_id: assigningBooking.booking_id,
      technician_id: selectedTechnician,
    }, {
      headers: {
        'Content-Type': 'application/json',
        'Session-ID': sessionId || '',
      },
    })
      .then((response) => {
        alert(response.data.message || 'Technician assigned!');
        window.location.reload();
      })
      .catch(() => {
        alert('Failed to assign technician. Please try again.');
      })
      .finally(() => setIsAssigning(false));
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center space-x-4">
              <button
                onClick={() => window.history.back()}
                className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
              >
                <FiArrowLeft className="w-5 h-5" />
              </button>
              <div className="w-10 h-10 bg-teal-600 rounded-lg flex items-center justify-center">
                <FiShield className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-semibold text-gray-900">NPC Admin</h1>
                <p className="text-sm text-gray-500">Administration Panel</p>
              </div>
            </div>
            
            <div className="flex items-center space-x-4">
              <div className="text-right">
                <p className="text-sm font-medium text-gray-900">Welcome,</p>
                <p className="text-sm text-gray-500">{user?.name || 'Admin'}</p>
              </div>
              <button
                onClick={handleLogout}
                className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
              >
                <FiLogOut className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
        >
          {/* Page Header */}
          <div className="mb-8">
            <h2 className="text-3xl font-bold text-gray-900 mb-2">Admin Dashboard</h2>
            <p className="text-gray-600">Manage your business operations</p>
          </div>

          {/* Statistics Cards */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
            {statsCards.map((stat, index) => (
              <motion.div
                key={stat.title}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.3, delay: index * 0.1 }}
                className="bg-white rounded-lg shadow-sm p-6"
              >
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">{stat.title}</p>
                    <p className="text-2xl font-bold text-gray-900">{stat.value}</p>
                    <p className="text-xs text-green-600 mt-1">{stat.change} from last month</p>
                  </div>
                  <div className={`w-12 h-12 ${stat.color} rounded-lg flex items-center justify-center`}>
                    <stat.icon className="w-6 h-6 text-white" />
                  </div>
                </div>
              </motion.div>
            ))}
          </div>

          {/* Tab Navigation */}
          <div className="mb-6">
            <div className="border-b border-gray-200">
              <nav className="-mb-px flex space-x-8">
                                 {[
                   { id: 'overview', label: 'Overview', icon: FiBarChart },
                  { id: 'bookings', label: 'Bookings', icon: FiCalendar },
                  { id: 'employees', label: 'Employees', icon: FiUsers },
                  { id: 'queries', label: 'Contact Queries', icon: FiSettings }
                ].map((tab) => (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)}
                    className={`py-2 px-1 border-b-2 font-medium text-sm transition-colors ${
                      activeTab === tab.id
                        ? 'border-teal-500 text-teal-600'
                        : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                    }`}
                  >
                    <tab.icon className="inline w-4 h-4 mr-1" />
                    {tab.label}
                  </button>
                ))}
              </nav>
            </div>
          </div>

          {/* Tab Content */}
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* Recent Bookings */}
              <div className="bg-white rounded-lg shadow-sm p-6">
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Recent Bookings</h3>
                {bookingsLoading ? (
                  <div className="flex justify-center py-8">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                  </div>
                ) : bookings.length === 0 ? (
                  <p className="text-gray-500 text-center py-8">No bookings found</p>
                ) : (
                  <div className="space-y-3">
                    {bookings.slice(0, 5).map((booking: Booking) => (
                      <div key={booking.booking_id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                        <div>
                          <p className="font-medium text-gray-900">{booking.service_name}</p>
                          <p className="text-sm text-gray-600">{formatDate(booking.service_date)}</p>
                        </div>
                        <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(String(booking.status || ''))}`}>
                          {booking.status}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Pending Queries */}
              <div className="bg-white rounded-lg shadow-sm p-6">
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Pending Contact Queries</h3>
                {queriesLoading ? (
                  <div className="flex justify-center py-8">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                  </div>
                ) : pendingQueries === 0 ? (
                  <p className="text-gray-500 text-center py-8">No pending queries</p>
                ) : (
                  <div className="space-y-3">
                    {queries.filter((q: ContactQuery) => (q as ContactQuery).status === 'pending').slice(0, 5).map((query: ContactQuery) => (
                      <div key={query.query_id} className="p-3 bg-gray-50 rounded-lg">
                        <p className="font-medium text-gray-900">{query.subject}</p>
                        <p className="text-sm text-gray-600">{query.first_name} {query.last_name}</p>
                        <p className="text-xs text-gray-500">{formatDate(query.created_at)}</p>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'bookings' && (
            <div className="bg-white rounded-lg shadow-sm overflow-hidden">
              <div className="px-6 py-4 border-b border-gray-200 flex flex-col md:flex-row md:items-center md:justify-between">
                <h3 className="text-lg font-semibold text-gray-900 mb-2 md:mb-0">All Bookings</h3>
                <div className="flex space-x-2">
                  <button
                    className={`px-4 py-2 rounded-lg text-sm font-medium border ${bookingsTab === 'all' ? 'bg-teal-600 text-white border-teal-600' : 'bg-white text-gray-700 border-gray-300'}`}
                    onClick={() => setBookingsTab('all')}
                  >
                    All
                  </button>
                  <button
                    className={`px-4 py-2 rounded-lg text-sm font-medium border ${bookingsTab === 'pending' ? 'bg-yellow-500 text-white border-yellow-500' : 'bg-white text-gray-700 border-gray-300'}`}
                    onClick={() => setBookingsTab('pending')}
                  >
                    Pending
                  </button>
                  <button
                    className={`px-4 py-2 rounded-lg text-sm font-medium border ${bookingsTab === 'accepted' ? 'bg-blue-500 text-white border-blue-500' : 'bg-white text-gray-700 border-gray-300'}`}
                    onClick={() => setBookingsTab('accepted')}
                  >
                    Accepted
                  </button>
                  <button
                    className={`px-4 py-2 rounded-lg text-sm font-medium border ${bookingsTab === 'completed' ? 'bg-green-500 text-white border-green-500' : 'bg-white text-gray-700 border-gray-300'}`}
                    onClick={() => setBookingsTab('completed')}
                  >
                    Completed
                  </button>
                </div>
              </div>
              {bookingsLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Service
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Date
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Amount
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Status
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {(bookingsTab === 'all' ? bookings :
                        bookings.filter((booking: Booking) => {
                          if (bookingsTab === 'pending') return booking.booking_status === 'pending';
                          if (bookingsTab === 'accepted') return ['accepted', 'confirmed', 'assigned', 'in_progress'].includes((booking.booking_status || '').toLowerCase());
                          if (bookingsTab === 'completed') return booking.booking_status === 'completed';
                          return true;
                        })
                      ).map((booking: Booking) => (
                        <tr key={booking.booking_id}>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm font-medium text-gray-900">{booking.service_name}</div>
                            <div className="text-sm text-gray-500">{booking.booking_id}</div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            {formatDate(booking.service_date)}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            ₹{booking.total_amount}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(String(booking.booking_status || ''))}`}>
                              {booking.booking_status}
                            </span>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <button className="btn btn-sm btn-outline mr-2" onClick={() => handleViewBooking(booking)}>View</button>
                            {(booking.booking_status === 'pending') && (
                              <button className="btn btn-sm btn-outline mr-2" disabled={isVerifying} onClick={() => handleVerifyBooking(booking.booking_id)}>
                                {isVerifying ? 'Verifying...' : 'Verify'}
                              </button>
                            )}
                            {(booking.booking_status === 'pending' || booking.booking_status === 'confirmed' || booking.booking_status === 'accepted') && (
                              <button className="btn btn-sm btn-outline" onClick={() => handleOpenAssignModal(booking)}>Assign</button>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}

          {activeTab === 'employees' && (
            <div className="bg-white rounded-lg shadow-sm overflow-hidden">
              <div className="px-6 py-4 border-b border-gray-200 flex justify-between items-center">
                <h3 className="text-lg font-semibold text-gray-900">Employees</h3>
                <button className="btn btn-primary text-sm">
                  <FiUserPlus className="w-4 h-4 mr-2" />
                  Add Employee
                </button>
              </div>
              {employeesLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Employee
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Contact
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Service Type
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Address
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Status
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Actions
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {employees.map((employee: Employee) => (
                        <tr key={employee.id}>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm font-medium text-gray-900">{employee.name}</div>
                            <div className="text-sm text-gray-500">{employee.email}</div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            {employee.mobile}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            {employee.serviceType}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            {employee.address}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className="px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800">
                              Active
                            </span>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <button
                              className="btn btn-sm btn-outline"
                              onClick={() => handleResetPassword(employee.id)}
                            >
                              Reset Password
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}

          {activeTab === 'queries' && (
            <div className="bg-white rounded-lg shadow-sm overflow-hidden">
              <div className="px-6 py-4 border-b border-gray-200">
                <h3 className="text-lg font-semibold text-gray-900">Contact Queries</h3>
              </div>
              {queriesLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Query
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Contact
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Date
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Status
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {queries.map((query: ContactQuery) => (
                        <tr key={query.query_id}>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm font-medium text-gray-900">{query.subject}</div>
                            <div className="text-sm text-gray-500 truncate max-w-xs">{query.message}</div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm text-gray-900">{query.first_name} {query.last_name}</div>
                            <div className="text-sm text-gray-500">{query.email}</div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            {formatDate(query.created_at)}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                              query.status === 'pending' ? 'bg-yellow-100 text-yellow-800' : 'bg-green-100 text-green-800'
                            }`}>
                              {query.status}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}
        </motion.div>
      </div>

      {/* Booking Details Modal */}
      <ReactModal
        isOpen={isBookingModalOpen}
        onRequestClose={handleCloseBookingModal}
        contentLabel="Booking Details"
        ariaHideApp={false}
        className="modal"
        overlayClassName="modal-overlay"
      >
        {selectedBooking && (
          <div className="p-6">
            <h2 className="text-2xl font-bold mb-4">Booking Details</h2>
            <div className="mb-2"><b>Service:</b> {selectedBooking.service_name}</div>
            <div className="mb-2"><b>Booking ID:</b> {selectedBooking.booking_id}</div>
            <div className="mb-2"><b>Date:</b> {selectedBooking.service_date_formatted || formatDate(selectedBooking.service_date)}</div>
            <div className="mb-2"><b>Time Slot:</b> {selectedBooking.time_slot}</div>
            <div className="mb-2"><b>Address:</b> {selectedBooking.service_address}</div>
            <div className="mb-2"><b>Customer Name:</b> {selectedBooking.customer_name}</div>
            <div className="mb-2"><b>Email:</b> {selectedBooking.customer_email}</div>
            <div className="mb-2"><b>Phone:</b> {selectedBooking.customer_phone}</div>
            <div className="mb-2"><b>Assigned Technician:</b> {selectedBooking.assigned_technician_name || 'Not assigned'}</div>
            <div className="mb-2"><b>Technician Phone:</b> {selectedBooking.technician_phone || 'N/A'}</div>
            <div className="mb-2"><b>Payment Method:</b> {selectedBooking.payment_method}</div>
            <div className="mb-2"><b>Payment Status:</b> {selectedBooking.payment_status}</div>
            <div className="mb-2"><b>Status:</b> {selectedBooking.booking_status}</div>
            <div className="mb-2"><b>Subtotal:</b> ₹{selectedBooking.subtotal}</div>
            <div className="mb-2"><b>Discount:</b> ₹{selectedBooking.discount_amount}</div>
            <div className="mb-2"><b>Total:</b> ₹{selectedBooking.total_amount}</div>
            <div className="mb-2"><b>Special Notes:</b> {selectedBooking.special_notes || 'None'}</div>
            <button className="btn btn-primary mt-4" onClick={handleCloseBookingModal}>Close</button>
          </div>
        )}
      </ReactModal>

      {/* Assign Technician Modal */}
      <ReactModal
        isOpen={isAssignModalOpen}
        onRequestClose={handleCloseAssignModal}
        contentLabel="Assign Technician"
        ariaHideApp={false}
        className="modal"
        overlayClassName="modal-overlay"
      >
        <div className="p-6">
          <h2 className="text-2xl font-bold mb-4">Assign Technician</h2>
          <select
            className="w-full p-2 border rounded mb-4"
            value={selectedTechnician}
            onChange={e => setSelectedTechnician(e.target.value)}
          >
            <option value="">Select Technician</option>
            {employees.map((tech: any) => (
              <option key={tech.id} value={tech.id}>{tech.name} ({tech.email})</option>
            ))}
          </select>
          <button className="btn btn-primary mr-2" disabled={isAssigning} onClick={handleAssignTechnician}>
            {isAssigning ? 'Assigning...' : 'Assign'}
          </button>
          <button className="btn btn-outline" onClick={handleCloseAssignModal}>Cancel</button>
        </div>
      </ReactModal>
    </div>
  );
};

export default AdminDashboard;
